import axios from "axios";

// Cache translations to reduce API calls
const translationCache = {};

// Fallback translation using a free service
const translateWithFallback = async (text, targetLang) => {
  // Try multiple free translation services
  const services = [
    {
      name: "LibreTranslate",
      url: "https://libretranslate.de/translate",
      method: "POST",
      data: {
        q: text,
        source: "en",
        target: targetLang,
        format: "text"
      }
    },
    {
      name: "ArgosTranslate",
      url: "https://translate.argosopentech.com/translate",
      method: "POST",
      data: {
        q: text,
        source: "en",
        target: targetLang,
        format: "text"
      }
    }
  ];

  for (const service of services) {
    try {
      console.log(`Trying ${service.name} for translation...`);

      const response = await axios({
        method: service.method,
        url: service.url,
        data: service.data,
        headers: {
          'Content-Type': 'application/json'
        },
        timeout: 5000
      });

      if (response.data && response.data.translatedText) {
        console.log(`Successfully translated via ${service.name}`);
        return response.data.translatedText;
      }
    } catch (error) {
      console.warn(`${service.name} failed:`, error.message);
      continue;
    }
  }

  throw new Error("All translation services failed");
};

export const translate = async (text, targetLang) => {
  // Return original text if target is English or no text
  if (!text || targetLang === "en") {
    return text;
  }

  // Check cache first
  const cacheKey = `${text}-${targetLang}`;
  if (translationCache[cacheKey]) {
    console.log("Using cached translation");
    return translationCache[cacheKey];
  }

  try {
    console.log(`Translating: "${text.substring(0, 50)}..." to ${targetLang}`);

    // Try your backend API first
    const backendUrl = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';
    const response = await axios.post(`${backendUrl}/translate`, {
      text,
      to: targetLang,
      from: "en"
    }, {
      timeout: 5000,
      headers: {
        'Content-Type': 'application/json'
      }
    });

    if (response.data && response.data.translatedText) {
      const translatedText = response.data.translatedText;

      // Cache the result
      translationCache[cacheKey] = translatedText;

      return translatedText;
    } else {
      console.warn("Backend translation API returned no translated text");
      // Fallback to free service
      return await translateWithFallback(text, targetLang);
    }
  } catch (error) {
    console.error("Backend translation failed:", error.message);

    // Try fallback services
    try {
      const translatedText = await translateWithFallback(text, targetLang);
      translationCache[cacheKey] = translatedText;
      return translatedText;
    } catch (fallbackError) {
      console.error("All translation attempts failed:", fallbackError.message);
      return text; // Return original text as last resort
    }
  }
};

// Clear cache function
export const clearTranslationCache = () => {
  Object.keys(translationCache).forEach(key => {
    delete translationCache[key];
  });
  console.log("Translation cache cleared");
};
